 id=models.UUIDField(primary_key=True,default=uuid.uuid4,editable=False);tenant=models.ForeignKey("users.Institution",on_delete=models.PROTECT,related_name="evidence_mapping_runs");intent=models.ForeignKey("self_study.SelfStudyIntent",on_delete=models.PROTECT,related_name="evidence_mapping_runs");graph_version=models.ForeignKey("self_study.CurriculumGraphVersion",on_delete=models.PROTECT,related_name="evidence_mapping_runs");status=models.CharField(max_length=32,choices=MappingRunStatus.choices,default=MappingRunStatus.PENDING);stage=models.CharField(max_length=32,default="CREATED");input_manifest=models.JSONField();run_fingerprint=models.CharField(max_length=128);algorithm_versions=models.JSONField();policy_version=models.CharField(max_length=64);requested_by=models.ForeignKey("users.User",on_delete=models.PROTECT,related_name="requested_evidence_mapping_runs");failure_code=models.CharField(max_length=96,blank=True);failure_detail=models.CharField(max_length=500,blank=True);predecessor=models.ForeignKey("self",null=True,blank=True,on_delete=models.PROTECT,related_name="successors");version=models.PositiveIntegerField(default=1);created_at=models.DateTimeField(auto_now_add=True);updated_at=models.DateTimeField(auto_now=True);completed_at=models.DateTimeField(null=True,blank=True)
 resources=models.ManyToManyField("academic.LearningResource",through="EvidenceMappingRunResource")
