 def save(self,*a,**kw):
  if self.pk:
   old=type(self).objects.filter(pk=self.pk).first()
   frozen=("tenant_id","intent_id","graph_version_id","input_manifest","run_fingerprint","algorithm_versions","policy_version","requested_by_id")
   if old and old.status in {MappingRunStatus.COMPLETED,MappingRunStatus.FAILED,MappingRunStatus.STALE,MappingRunStatus.INVALIDATED,MappingRunStatus.SUPERSEDED} and any(getattr(old,x)!=getattr(self,x) for x in frozen):raise ValidationError("Terminal mapping inputs are immutable.",code="MAPPING_INPUT_MANIFEST_INVALID")
  super().save(*a,**kw)
